    ));

    $socials = get_field('socials', 'option');
    $footer_group = get_field('footer', 'option');
    $footer_logo = is_array($footer_group) && !empty($footer_group['footerlogo']) ? $footer_group['footerlogo'] : get_field('footerlogo', 'option');
